+++ b/tests/auth.test.ts
@@ -0,0 +1,34 @@
+import { describe, test, expect } from 'bun:test';
+import { verifyToken, generateToken } from '../src/auth';
+
+describe('auth', () => {
+  test('generates valid JWT token', () => {
+    const token = generateToken({ userId: '123' });
+    expect(token).toBeTruthy();
+    expect(typeof token).toBe('string');
+  });
+
+  test('verifies valid token', async () => {
+    const token = generateToken({ userId: '123' });
+    const decoded = await verifyToken(token);
+    expect(decoded.userId).toBe('123');
+  });
+
+  test('rejects expired token', async () => {
+    const token = generateToken({ userId: '123' }, { expiresIn: -1 });
+    expect(verifyToken(token)).rejects.toThrow('Token expired');
+  });
+});

